{
  "recipes": [
    {
      "name": "Authentic Mapo Tofu (麻婆豆腐)",
      "instructions": [
        "Cut the silken tofu into 2cm cubes and blanch them in boiling salted water for 1-2 minutes to firm them up. Drain gently.",
        "Finely mince the garlic and ginger. Finely chop the scallions, separating the white and green parts.",
        "Toast the Sichuan peppercorns in a dry wok over low heat until fragrant, then grind them into a fine powder and set aside.",
        "Heat oil in the wok, add the minced beef, and stir-fry until crispy and brown.",
        "Add the Pixian Doubanjiang and stir-fry on low heat until the oil turns red.",
        "Add the garlic, ginger, and scallion whites, stir-frying until fragrant.",
        "Pour in the chicken broth, light soy sauce, and Shaoxing rice wine. Bring to a simmer.",
        "Gently slide in the tofu cubes. Simmer for 3-5 minutes on low heat to let the tofu absorb the flavors.",
        "Drizzle in the cornstarch slurry in three stages, stirring extremely gently to thicken the sauce without breaking the tofu.",
        "Turn off the heat, transfer to a serving bowl, sprinkle with the ground Sichuan peppercorn powder, and garnish with scallion greens."
      ],
      "required_ingredients": [
        {
          "name": "silken tofu",
          "amount": "400g"
        },
        {
          "name": "minced beef",
          "amount": "100g"
        },
        {
          "name": "garlic",
          "amount": "3 cloves"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
        {
          "name": "Pixian Doubanjiang",
          "amount": "2 tbsp"
        },
        {
          "name": "Sichuan Peppercorns",
          "amount": "1 tsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Cornstarch",
          "amount": "1 tbsp"
        },
        {
          "name": "Scallions",
          "amount": "2 stalks"
        },
        {
          "name": "Chicken Broth",
          "amount": "150ml"
        }
      ],
      "missing_ingredients": [
        "Pixian Doubanjiang",
        "Sichuan Peppercorns",
        "Shaoxing Rice Wine",
        "Light Soy Sauce",
        "Cornstarch",
        "Scallions",
        "Chicken Broth"
      ]
    },
    {
      "name": "Sichuan Spicy Beef and Tofu Soup (牛肉豆腐羹)",
      "instructions": [
        "Marinate the minced beef with a pinch of salt, white pepper powder, and Shaoxing rice wine for 10 minutes.",
        "Cut the silken tofu into small 1cm cubes. Mince the garlic and ginger.",
        "Heat a little oil in a pot, saute the ginger and garlic until fragrant.",
        "Add the marinated minced beef and stir-fry quickly to break it up.",
        "Pour in water or broth, bring to a boil, and skim off any foam from the surface.",
        "Gently add the silken tofu cubes and simmer for 5 minutes.",
        "Season with light soy sauce, salt, and white pepper powder.",
        "Slowly stir in the cornstarch slurry to create a thick, glossy soup consistency.",
        "Turn off the heat, stir in the Sichuan chili oil, and garnish with chopped scallions and coriander."
      ],
      "required_ingredients": [
        {
          "name": "silken tofu",
          "amount": "300g"
        },
        {
          "name": "minced beef",
          "amount": "100g"
        },
        {
          "name": "garlic",
          "amount": "2 cloves"
        },
        {
          "name": "ginger",
          "amount": "10g"
        },
        {
          "name": "White Pepper Powder",
          "amount": "1/2 tsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Cornstarch",
          "amount": "2 tbsp"
        },
        {
          "name": "Sichuan Chili Oil",
          "amount": "1 tbsp"
        },
        {
          "name": "Scallions",
          "amount": "1 stalk"
        },
        {
          "name": "Coriander",
          "amount": "1 sprig"
        }
      ],
      "missing_ingredients": [
        "White Pepper Powder",
        "Shaoxing Rice Wine",
        "Light Soy Sauce",
        "Cornstarch",
        "Sichuan Chili Oil",
        "Scallions",
        "Coriander"
      ]
    },
    {
      "name": "Sichuan Homestyle Tofu with Beef (家常豆腐)",
      "instructions": [
        "Carefully slice the silken tofu into thick rectangles. Pan-fry them gently in a non-stick skillet with oil until lightly golden on both sides. Set aside.",
        "Mince the garlic and ginger. Slice the scallions.",
        "Heat oil in a wok, add the minced beef, and stir-fry until cooked through.",
        "Push the beef to the side, add Pixian Doubanjiang to the center, and fry on low heat until the oil is red and aromatic.",
        "Incorporate the garlic, ginger, and scallion whites into the meat and paste.",
        "Add a splash of Shaoxing rice wine and light soy sauce, then pour in 100ml of water.",
        "Slide the pan-fried tofu back into the wok. Simmer gently for 3-4 minutes to allow the tofu to absorb the savory, spicy sauce.",
        "Thicken the sauce with a light cornstarch slurry, gently folding to avoid breaking the tofu.",
        "Finish with Sichuan chili oil and a scatter of green scallions before serving."
      ],
      "required_ingredients": [
        {
          "name": "silken tofu",
          "amount": "400g"
        },
        {
          "name": "minced beef",
          "amount": "150g"
        },
        {
          "name": "garlic",
          "amount": "3 cloves"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
        {
          "name": "Pixian Doubanjiang",
          "amount": "1.5 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tbsp"
        },
        {
          "name": "Scallions",
          "amount": "2 stalks"
        },
        {
          "name": "Cornstarch",
          "amount": "1 tsp"
        },
        {
          "name": "Sichuan Chili Oil",
          "amount": "1 tbsp"
        }
      ],
      "missing_ingredients": [
        "Pixian Doubanjiang",
        "Light Soy Sauce",
        "Shaoxing Rice Wine",
        "Scallions",
        "Cornstarch",
        "Sichuan Chili Oil"
      ]
    }
  ]
}

{
  "recipes": [
    {
      "name": "Classic Cantonese Steamed Sea Bass (清蒸鱸魚)",
      "instructions": [
        "Julienne the ginger and spring onions into very fine shreds, keeping the green and white parts of the spring onions separate. Soak them in cold water to curl.",
        "Pat the sea bass fillets dry with paper towels. Place a few slices of ginger underneath the fillets on a heatproof steaming plate.",
        "Set up a steamer over high heat. Once the water is boiling rapidly, place the plate with the fish inside, cover, and steam for 6-8 minutes until the flesh is opaque and flakes easily.",
        "Carefully discard any accumulated fish liquid on the plate and remove the steamed ginger slices.",
        "Scatter the fresh julienned ginger and spring onions over the steamed fish.",
        "In a small saucepan, heat the vegetable oil until smoking hot, then carefully pour it over the ginger and spring onions to release their aroma.",
        "Combine the light soy sauce, seasoned soy sauce for seafood, Shaoxing rice wine, and white pepper. Pour this sauce mixture around the sides of the fish (not directly over the top) and serve immediately."
      ],
      "required_ingredients": [
        {
          "name": "Sea bass fillets",
          "amount": "2 fillets (approx. 250g)"
        },
        {
          "name": "Ginger",
          "amount": "30g"
        },
        {
          "name": "Spring onions",
          "amount": "3 stalks"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Seasoned Soy Sauce for Seafood",
          "amount": "2 tbsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tsp"
        },
        {
          "name": "Vegetable Oil",
          "amount": "2 tbsp"
        },
        {
          "name": "White Pepper Powder",
          "amount": "a pinch"
        }
      ],
      "missing_ingredients": [
        "Light Soy Sauce",
        "Seasoned Soy Sauce for Seafood",
        "Shaoxing Rice Wine",
        "Vegetable Oil",
        "White Pepper Powder"
      ]
    },
    {
      "name": "Steamed Sea Bass with Black Bean Sauce (豉汁蒸鱸魚)",
      "instructions": [
        "Finely mince the fermented black beans and garlic together to form a coarse paste.",
        "Finely shred the ginger and chop the spring onions.",
        "Pat the sea bass fillets dry. Rub a tiny pinch of salt and a splash of Shaoxing rice wine over them, then place them on a heatproof plate.",
        "Spread the black bean and garlic paste evenly on top of the sea bass fillets, and top with the shredded ginger.",
        "Steam over high heat for 6-8 minutes until cooked through.",
        "Garnish with chopped spring onions, drizzle with hot vegetable oil, and finish with a splash of light soy sauce."
      ],
      "required_ingredients": [
        {
          "name": "Sea bass fillets",
          "amount": "2 fillets"
        },
        {
          "name": "Ginger",
          "amount": "15g"
        },
        {
          "name": "Spring onions",
          "amount": "2 stalks"
        },
        {
          "name": "Fermented Black Beans",
          "amount": "1 tbsp"
        },
        {
          "name": "Garlic",
          "amount": "2 cloves"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tsp"
        },
        {
          "name": "Vegetable Oil",
          "amount": "1 tbsp"
        },
        {
          "name": "Salt",
          "amount": "a pinch"
        }
      ],
      "missing_ingredients": [
        "Fermented Black Beans",
        "Garlic",
        "Shaoxing Rice Wine",
        "Light Soy Sauce",
        "Vegetable Oil"
      ]
    },
    {
      "name": "Steamed Sea Bass with Shiitake and Wood Ear Mushrooms (金針雲耳蒸鱸魚)",
      "instructions": [
        "Rehydrate the dried shiitake mushrooms and wood ear mushrooms in warm water until soft, then slice them into thin strips.",
        "Cut the sea bass fillets into bite-sized pieces. Marinate with julienned ginger, light soy sauce, Shaoxing rice wine, cornstarch, and sugar for 10 minutes.",
        "Spread the rehydrated mushrooms onto a steaming plate, then arrange the marinated fish pieces in a single layer on top.",
        "Steam over high heat for 7-8 minutes.",
        "Scatter chopped spring onions and a dash of sesame oil over the fish before serving."
      ],
      "required_ingredients": [
        {
          "name": "Sea bass fillets",
          "amount": "2 fillets"
        },
        {
          "name": "Ginger",
          "amount": "20g"
        },
        {
          "name": "Spring onions",
          "amount": "2 stalks"
        },
        {
          "name": "Dried Shiitake Mushrooms",
          "amount": "4 pieces"
        },
        {
          "name": "Dried Wood Ear Mushrooms",
          "amount": "5g"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1.5 tbsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tbsp"
        },
        {
          "name": "Cornstarch",
          "amount": "1/2 tsp"
        },
        {
          "name": "Sugar",
          "amount": "1/4 tsp"
        },
        {
          "name": "Sesame Oil",
          "amount": "1 tsp"
        }
      ],
      "missing_ingredients": [
        "Dried Shiitake Mushrooms",
        "Dried Wood Ear Mushrooms",
        "Light Soy Sauce",
        "Shaoxing Rice Wine",
        "Cornstarch",
        "Sesame Oil"
      ]
    }
  ]
}

{
  "recipes": [
    {
      "name": "Hong Shao Rou (Red Braised Pork Belly)",
      "instructions": [
        "Cut the pork belly into 2cm cubes. Slice the ginger and crush the garlic.",
        "Blanch the pork belly cubes in boiling water with some ginger slices and a splash of Shaoxing wine for 3-4 minutes to remove impurities, then drain and set aside.",
        "In a wok or heavy-bottomed pot, heat cooking oil and rock sugar over low heat until the sugar melts and turns a light amber caramel color.",
        "Immediately add the pork belly to the caramelized sugar and stir-fry quickly to coat the pork evenly.",
        "Add garlic, ginger, star anise, and cinnamon stick, and stir-fry until fragrant.",
        "Pour in the Shaoxing rice wine, light soy sauce, dark soy sauce, and enough boiling water to just cover the pork.",
        "Bring to a boil, then cover and simmer on low heat for 50-60 minutes until the pork is tender.",
        "Uncover and turn up the heat to high, stirring constantly, to reduce the sauce until it is thick and glossy, coating the pork belly."
      ],
      "required_ingredients": [
        {
          "name": "pork belly",
          "amount": "500g"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
        {
          "name": "garlic",
          "amount": "3 cloves"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "2 tbsp"
        },
        {
          "name": "Dark Soy Sauce",
          "amount": "1 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1.5 tbsp"
        },
        {
          "name": "Rock Sugar",
          "amount": "30g"
        },
        {
          "name": "Star Anise",
          "amount": "2 pieces"
        },
        {
          "name": "Cinnamon Stick",
          "amount": "1 piece"
        },
        {
          "name": "Cooking Oil",
          "amount": "1 tbsp"
        }
      ],
      "missing_ingredients": [
        "Shaoxing Rice Wine",
        "Dark Soy Sauce",
        "Light Soy Sauce",
        "Rock Sugar",
        "Star Anise",
        "Cinnamon Stick",
        "Cooking Oil"
      ]
    },
    {
      "name": "Hui Guo Rou (Twice-Cooked Pork)",
      "instructions": [
        "Place the whole slab of pork belly in a pot with water, ginger slices, and a splash of Shaoxing wine. Bring to a boil and simmer for 20 minutes until just cooked through. Remove, let cool, and slice thinly.",
        "Slice the leeks diagonally into 1-inch sections, separating white and green parts.",
        "Heat a wok over medium heat. Add the pork belly slices in a single layer and fry until they start to curl and release their oil. Remove excess grease if there is too much.",
        "Push the pork to the side of the wok. Add Pixian Doubanjiang and fermented black beans to the oil in the center, frying until the oil turns red and fragrant.",
        "Add garlic and ginger slices, stirring to combine with the pork and paste.",
        "Add the white parts of the leeks, light soy sauce, and sugar. Stir-fry for 1 minute.",
        "Add the green parts of the leeks, toss quickly until wilted, and transfer to a serving plate."
      ],
      "required_ingredients": [
        {
          "name": "pork belly",
          "amount": "400g"
        },
        {
          "name": "ginger",
          "amount": "15g"
        },
        {
          "name": "garlic",
          "amount": "3 cloves"
        },
        {
          "name": "Pixian Doubanjiang",
          "amount": "1.5 tbsp"
        },
        {
          "name": "Fermented Black Beans",
          "amount": "1 tbsp"
        },
        {
          "name": "Leeks",
          "amount": "150g"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "1 tsp"
        },
        {
          "name": "Shaoxing Rice Wine",
          "amount": "1 tbsp"
        },
        {
          "name": "Sugar",
          "amount": "1 tsp"
        }
      ],
      "missing_ingredients": [
        "Pixian Doubanjiang",
        "Fermented Black Beans",
        "Leeks",
        "Light Soy Sauce",
        "Shaoxing Rice Wine",
        "Sugar"
      ]
    },
    {
      "name": "Suan Ni Bai Rou (Sichuan Garlic Pork Belly)",
      "instructions": [
        "Boil the pork belly in a pot with water, ginger slices, and Sichuan peppercorns for about 25-30 minutes until fully cooked and tender.",
        "While the pork is cooking, finely grate the garlic to make a paste. Mix it with light soy sauce, Sichuan chili oil, Chinkiang vinegar, sugar, and sesame oil to make the garlic sauce.",
        "Remove the pork belly from the water, let it cool completely, then slice it as thinly as possible.",
        "Arrange the pork belly slices on a serving plate, overlapping them slightly.",
        "Pour the prepared garlic soy sauce dressing evenly over the pork belly slices and serve cool or at room temperature."
      ],
      "required_ingredients": [
        {
          "name": "pork belly",
          "amount": "400g"
        },
        {
          "name": "garlic",
          "amount": "6 cloves"
        },
        {
          "name": "ginger",
          "amount": "10g"
        },
        {
          "name": "Sichuan Chili Oil",
          "amount": "3 tbsp"
        },
        {
          "name": "Light Soy Sauce",
          "amount": "2 tbsp"
        },
        {
          "name": "Chinkiang Vinegar",
          "amount": "1 tbsp"
        },
        {
          "name": "Sugar",
          "amount": "1 tsp"
        },
        {
          "name": "Sichuan Peppercorns",
          "amount": "1 tsp"
        },
        {
          "name": "Sesame Oil",
          "amount": "1 tsp"
        }
      ],
      "missing_ingredients": [
        "Sichuan Chili Oil",
        "Light Soy Sauce",
        "Chinkiang Vinegar",
        "Sugar",
        "Sichuan Peppercorns",
        "Sesame Oil"
      ]
    }
  ]
}
